// --- hooks.ts ---
import { useMemo } from 'react';
import type { WeatherCardProps, WeatherHookReturn } from './types';

/**
 * Custom hook for processing weather data and providing formatted display values.
 * 
 * @param props - The raw weather data props including temperature, humidity, wind speed, and units.
 * @returns Formatted strings for temperature, wind, humidity, the unit label, and the current date.
 */
export function useWeather(props: WeatherCardProps): WeatherHookReturn {
  const {
    temperature = 0,
    humidity = 0,
    windSpeed = 0,
    unit = 'C',
  } = props;

  return useMemo(() => {
    // Round the temperature prop to the nearest whole number and convert it to a string.
    const formattedTemp = Math.round(temperature ?? 0).toString();

    // Format the humidity prop as a percentage string (e.g., "85%").
    // We round it to ensure it's a whole number for consistent display.
    const formattedHumidity = `${Math.round(humidity ?? 0)}%`;

    // Format the windSpeed prop with one decimal place and append the appropriate unit.
    // Metric (C) uses "km/h", Imperial (F) uses "mph".
    const displayWindValue = (windSpeed ?? 0).toFixed(1);
    const windUnitLabel = unit === 'F' ? 'mph' : 'km/h';
    const formattedWind = `${displayWindValue} ${windUnitLabel}`;

    // Convert the unit prop into a display label (e.g., "°C" or "°F").
    const unitLabel = unit === 'F' ? '°F' : '°C';

    // Generate a human-readable date string for the current day.
    // Format: "Monday, July 10"
    const dateOptions: Intl.DateTimeFormatOptions = {
      weekday: 'long',
      month: 'long',
      day: 'numeric',
    };
    const currentDate = new Intl.DateTimeFormat('en-US', dateOptions).format(new Date());

    return {
      formattedTemp,
      formattedWind,
      formattedHumidity,
      unitLabel,
      currentDate,
    };
  }, [temperature, humidity, windSpeed, unit]);
}


